select com_name
from company
where com_id=#{comId}

select f.for_id, f.com_id, f.for_code, f.for_title, f.for_content, f.for_status, f.created_at, f.updated_at, f.for_version, c.com_name as comName from appr_form f left outer join company c on f.com_id = c.com_id
and f.com_id = #{comId}
and f.for_status = #{forStatus}
and ( f.for_code like '%' || #{keyword} || '%' or f.for_title like '%' || #{keyword} || '%' )
order by f.for_id desc, f.for_version desc offset #{pstartno} rows fetch next #{onepagelist} rows only

	select count(*)
	from appr_form


			and com_id = #{comId}


			and for_status = #{forStatus}


            and (
                for_code like '%' || #{keyword} || '%'
                or for_title like '%' || #{keyword} || '%'
            )

select * 
from appr_form


		and com_id = #{comId}


		and for_status = #{forStatus}


	and(
		for_code like '%' || #{keyword} || '%'
		or for_title like '%' ||  #{keyword} || '%'
	)


order by for_id desc offset #{pstartno} rows fetch next 10 rows only
